mapper.select:
 
		 
		select 
			db, owner, table_name, column_name, column_id, pk_yn, pk_position, full_data_type, data_type, data_length, nullable, comments, regdate, upddate, reguserid, upduserid
		from ( 
				select 
					 ROWNUM rn, db, owner, table_name, column_name, column_id, pk_yn, pk_position, full_data_type, data_type, data_length, nullable, comments, regdate, upddate, reguserid, upduserid
				from (
						select db, owner, table_name, column_name, column_id, pk_yn, pk_position, full_data_type, data_type, data_length, nullable, comments, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piitable order by db, owner, table_name, column_id
					 ) b
				where 
		
	    
		
						
							and upper(db) = upper(#{search4})
						
						
							and upper(owner) = upper(#{search5})
						
						
							and upper(table_name) = upper(#{search6})
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by db, owner, table_name, column_id
			  ) d
		where rn > (#{pagenum} -1) * #{amount} 
		order by db, owner, table_name, column_id

 
		 
		select 
			db, owner, table_name
		from ( 
				select 
					 ROWNUM rn, db, owner, table_name
				from (
						select db, owner, table_name
						  from cotdl.tbl_piitable 
						  
	    
								
										
											and upper(db) = upper(#{search4})
										
										
											and upper(owner) like upper(#{search5})||'%'
										
										
											and upper(table_name) like upper(#{search6})||'%'
										
								
	    
	    				
						  group by db, owner, table_name
						  order by db, owner, table_name
					 ) c
				where 

				 ROWNUM <= #{pagenum} * #{amount} 
				order by db, owner, table_name
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by db, owner, table_name
